refsection.programlisting:
// Create a file with some data separated with tabs.
M = 1:50;
filename = fullfile(TMPDIR, "datas.csv");
csv_write(M, filename, ascii(9), '.');

// read csv file
M1 = csv_read(filename,ascii(9))

// Returns a double
M2 = csv_read(filename,ascii(9), '.', 'double')

// Compares original data and result.
and(M == M2)

// Use the substitude argument to manage
// special data files.
content = [
"1"
"Not-A-Number"
"2"
"Not-A-Number"
];
substitute = [
"Not-A-Number" "Nan"
];
mputl(content,filename);
M = csv_read(filename,",",".","double",substitute)
isnan(M(2,1)) // Expected=%t
isnan(M(4,1)) // Expected=%t
